// Serve logo
app.get("/logo.png", (req, res) => {
  const base64Data = SD_LOGO.replace(/^data:image\/png;base64,/, "");
  const imgBuffer = Buffer.from(base64Data, "base64");
  res.setHeader("Content-Type", "image/png");
  res.send(imgBuffer);
});

