// ============================================
// HELPER FUNCTIONS
// ============================================
async function injectBundleCode(shop, accessToken) {
  const headers = { "X-Shopify-Access-Token": accessToken, "Content-Type": "application/json" };
  const themesRes = await fetch(`https://${shop}/admin/api/2023-10/themes.json`, { headers });
  const themesData = await themesRes.json();
  const activeTheme = themesData.themes.find((t) => t.role === "main");
  if (!activeTheme) throw new Error("No active theme found");

  const fileRes = await fetch(
    `https://${shop}/admin/api/2023-10/themes/${activeTheme.id}/assets.json?asset[key]=sections/product-template.liquid`,
    { headers }
  );
  const fileData = await fileRes.json();
  if (!fileData.asset) throw new Error("product-template.liquid not found. This theme may not be compatible.");

  let content = fileData.asset.value;
  if (content.includes("<!-- started of bundel -->")) return { alreadyInstalled: true };

  const target = `{% when 'custom' %}
							{{blockTitle}}
							<div id="tab{{block.id}}" class="{{tabClass}} rte">{{block.settings.content}}</div>`;

  if (!content.includes(target)) throw new Error("Injection point not found. This theme may not be compatible.");

  content = content.replace(target, `{% when 'custom' %}
							{{blockTitle}}
							<div id="tab{{block.id}}" class="{{tabClass}} rte">{{block.settings.content}}</div>
              ${BUNDLE_LIQUID}`);
  content = content.replace("{% schema %}", `${BUNDLE_CSS}\n\n{% schema %}`);

  await fetch(`https://${shop}/admin/api/2023-10/themes/${activeTheme.id}/assets.json`, {
    method: "PUT",
    headers,
    body: JSON.stringify({ asset: { key: "sections/product-template.liquid", value: content } }),
  });

  return { alreadyInstalled: false };
}

async function registerWebhook(shop, accessToken) {
  await fetch(`https://${shop}/admin/api/2023-10/webhooks.json`, {
    method: "POST",
    headers: { "X-Shopify-Access-Token": accessToken, "Content-Type": "application/json" },
    body: JSON.stringify({
      webhook: { topic: "app/uninstalled", address: `${process.env.HOST}/webhooks/app/uninstalled`, format: "json" },
    }),
  });
}

